exercise.solution:
function gradeReport(name, score) {
  let grade;
  if (score >= 90) {
    grade = "A";
  } else if (score >= 80) {
    grade = "B";
  } else if (score >= 70) {
    grade = "C";
  } else {
    grade = "F";
  }
  return `${name} scored ${score} — that's a ${grade}!`;
}

console.log(gradeReport("Sam", 85));    // Sam scored 85 — that's a B!
console.log(gradeReport("Alex", 72));   // Alex scored 72 — that's a C!
console.log(gradeReport("Jordan", 95)); // Jordan scored 95 — that's a A!
